sql.where:
a.status = 'PUBLISHED'

  and c.slug = #{category}


  and exists (select 1 from article_tags at2 join tags t2 on t2.id = at2.tag_id where at2.article_id = a.id and t2.slug = #{tag})


  and extract(year from a.published_at) = #{year}


  and extract(month from a.published_at) = #{month}

a.status = 'PUBLISHED'

  and (lower(a.title) like #{keyword}
    or lower(a.summary) like #{keyword}
    or lower(a.content_text) like #{keyword})

mapper.select:
select at.article_id, t.id, t.name, '/tag/' || t.slug as url from tags t join article_tags at on at.tag_id = t.id where at.article_id in
#{articleId}
order by at.article_id, t.id
